import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def distance(a, b):
        return np.linalg.norm(a - b)

    if len(unvisited_customers) == 0:
        return None  # No more customers to visit

    distances = np.array([distance(cur_truck_pos, customer) for customer in unvisited_customers])
    target_indices = []

    for other_truck in all_truck_pos:
        if not np.array_equal(other_truck, cur_truck_pos):
            other_distances = np.array([distance(other_truck, customer) for customer in unvisited_customers])
            target_indices.append(np.argmin(other_distances))

    unique_targets = [idx for idx in range(len(unvisited_customers)) if idx not in target_indices]

    if unique_targets:
        best_node = unique_targets[np.argmin(distances[unique_targets])]
    else:
        best_node = np.argmin(distances)  # Default to nearest if all targets are claimed

    return best_node
